import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"LEO 衛星與特殊應用 PCB 研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/PCB研究/LEO衛星與特殊應用PCB研究.md","filePath":"Deep32Q知識庫/產業洞察/PCB研究/LEO衛星與特殊應用PCB研究.md"}'),s={name:"Deep32Q知識庫/產業洞察/PCB研究/LEO衛星與特殊應用PCB研究.md"};function n(d,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="leo-衛星與特殊應用-pcb-研究" tabindex="-1">LEO 衛星與特殊應用 PCB 研究 <a class="header-anchor" href="#leo-衛星與特殊應用-pcb-研究" aria-label="Permalink to &quot;LEO 衛星與特殊應用 PCB 研究&quot;">​</a></h1><p><strong>更新日期：2026-05-13</strong></p><hr><h2 id="_1-leo-衛星-pcb-市場" tabindex="-1">1. LEO 衛星 PCB 市場 <a class="header-anchor" href="#_1-leo-衛星-pcb-市場" aria-label="Permalink to &quot;1. LEO 衛星 PCB 市場&quot;">​</a></h2><h3 id="starlink-低軌衛星生態系" tabindex="-1">Starlink 低軌衛星生態系 <a class="header-anchor" href="#starlink-低軌衛星生態系" aria-label="Permalink to &quot;Starlink 低軌衛星生態系&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:left;">數值（2025–2026）</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">Starlink 活躍衛星數（2025）</td><td style="text-align:left;">&gt;9,000 顆（V2 Mini 為主）</td><td style="text-align:left;">PCMag (2025)</td></tr><tr><td style="text-align:left;">Starlink 用戶數（2025）</td><td style="text-align:left;">&gt;900 萬訂閱者</td><td style="text-align:left;">PCMag (2025)</td></tr><tr><td style="text-align:left;">Bastrop 廠年產量（2025）</td><td style="text-align:left;">~8M kits</td><td style="text-align:left;">PCMag (2025)</td></tr><tr><td style="text-align:left;">Bastrop 廠年產量（2026 預估）</td><td style="text-align:left;">&gt;16M kits（翻倍）</td><td style="text-align:left;">PCMag (2025)</td></tr><tr><td style="text-align:left;">2026 發射計畫</td><td style="text-align:left;">V3 衛星（Starship 載運）</td><td style="text-align:left;">PCMAG (2025)</td></tr></tbody></table><h3 id="spacex-bastrop-pcb-製造基地" tabindex="-1">SpaceX Bastrop PCB 製造基地 <a class="header-anchor" href="#spacex-bastrop-pcb-製造基地" aria-label="Permalink to &quot;SpaceX Bastrop PCB 製造基地&quot;">​</a></h3><ul><li><strong>地點</strong>：Texas, Bastrop</li><li><strong>地位</strong>：美國最大的 PCB 製造廠（2025–2026）</li><li><strong>策略</strong>：垂直整合，PCB + PCBA 在廠內完成</li><li><strong>2026 目標</strong>：產能翻倍至 &gt;16M kits/年</li></ul><h3 id="華通-2313-—-leo-衛星板亞洲主力供應商" tabindex="-1">華通 (2313) — LEO 衛星板亞洲主力供應商 <a class="header-anchor" href="#華通-2313-—-leo-衛星板亞洲主力供應商" aria-label="Permalink to &quot;華通 (2313) — LEO 衛星板亞洲主力供應商&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>SpaceX Starlink 市佔</strong></td><td style="text-align:left;">「天上板」~90%（全球最高）</td></tr><tr><td style="text-align:left;"><strong>地面接收站</strong></td><td style="text-align:left;">主要供應商之一</td></tr><tr><td style="text-align:left;"><strong>亞馬遜 Project Kuiper</strong></td><td style="text-align:left;">已切入供應鏈</td></tr><tr><td style="text-align:left;"><strong>2025 預估全年營收</strong></td><td style="text-align:left;">~NT$760B（+4.9% YoY）</td></tr><tr><td style="text-align:left;"><strong>2025 LEO 板營收</strong></td><td style="text-align:left;">&gt;NT$151B（佔總營收 ~20–22%）</td></tr><tr><td style="text-align:left;"><strong>2026 預估全年營收</strong></td><td style="text-align:left;">NT$850–900B（法人預估）</td></tr><tr><td style="text-align:left;"><strong>2026 LEO 板營收</strong></td><td style="text-align:left;">&gt;NT$200B（佔比提升至 ~26%+）</td></tr><tr><td style="text-align:left;"><strong>LEO 板營收年增率</strong></td><td style="text-align:left;">&gt;30–47%（2026）</td></tr><tr><td style="text-align:left;"><strong>泰國新廠</strong></td><td style="text-align:left;">月產能 40 萬平方英尺，2026 Q1 全製程生產</td></tr><tr><td style="text-align:left;"><strong>2026 EPS 預估</strong></td><td style="text-align:left;">NT$7–8.51 元</td></tr></tbody></table><p><strong>來源：CTEE (2026/02), cnyes.com, digitimes.com</strong></p><h3 id="leo-衛星-pcb-技術門檻" tabindex="-1">LEO 衛星 PCB 技術門檻 <a class="header-anchor" href="#leo-衛星-pcb-技術門檻" aria-label="Permalink to &quot;LEO 衛星 PCB 技術門檻&quot;">​</a></h3><ol><li><strong>高可靠度</strong>：太空輻射耐受、真空環境適應</li><li><strong>小型化 + 輕量化</strong>：HDI 技術滿足衛星體積限制</li><li><strong>高頻 RF PCB</strong>：相控陣列天線用高频材料（PTFE/Rogers）</li><li><strong>量產能力</strong>：Starlink 年產 8M→16M kits，需要大規模 PCB 供應</li></ol><hr><h2 id="_2-車用-pcb" tabindex="-1">2. 車用 PCB <a class="header-anchor" href="#_2-車用-pcb" aria-label="Permalink to &quot;2. 車用 PCB&quot;">​</a></h2><h3 id="ev-vs-燃油車-pcb-用量對比" tabindex="-1">EV vs 燃油車 PCB 用量對比 <a class="header-anchor" href="#ev-vs-燃油車-pcb-用量對比" aria-label="Permalink to &quot;EV vs 燃油車 PCB 用量對比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">燃油車</th><th style="text-align:left;">EV（電動車）</th><th style="text-align:left;">差異</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>PCB 價值量</strong></td><td style="text-align:left;">$50–80/台</td><td style="text-align:left;">$100–150/台</td><td style="text-align:left;">2–3 倍</td></tr><tr><td style="text-align:left;"><strong>主要 PCB 類型</strong></td><td style="text-align:left;">多層板、簡單 HDI</td><td style="text-align:left;">高層數 HDI、厚銅板、柔性板</td><td style="text-align:left;">技術升級</td></tr><tr><td style="text-align:left;"><strong>關鍵應用</strong></td><td style="text-align:left;">引擎控制、儀表板</td><td style="text-align:left;">ADAS、電池管理、電控系統</td><td style="text-align:left;">更多高階板</td></tr></tbody></table><h3 id="車用-pcb-關鍵趨勢" tabindex="-1">車用 PCB 關鍵趨勢 <a class="header-anchor" href="#車用-pcb-關鍵趨勢" aria-label="Permalink to &quot;車用 PCB 關鍵趨勢&quot;">​</a></h3><ul><li><strong>ADAS 高層數 HDI</strong>：自動駕駛需要更多感測器 → 更高層數 PCB</li><li><strong>功率電子厚銅板</strong>：電機驅動、充電系統需要 &gt;3oz 厚銅</li><li><strong>柔性板（FPC）</strong>：電池模組、感測器連接用 FPC 需求上升</li><li><strong>台灣供應商</strong>：健鼎、燿華、楠梓電等均有車用 PCB 產能</li></ul><hr><h2 id="_3-高頻通訊-pcb" tabindex="-1">3. 高頻通訊 PCB <a class="header-anchor" href="#_3-高頻通訊-pcb" aria-label="Permalink to &quot;3. 高頻通訊 PCB&quot;">​</a></h2><h3 id="_5g-6g-基地台與低軌衛星通訊" tabindex="-1">5G/6G 基地台與低軌衛星通訊 <a class="header-anchor" href="#_5g-6g-基地台與低軌衛星通訊" aria-label="Permalink to &quot;5G/6G 基地台與低軌衛星通訊&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">應用領域</th><th style="text-align:left;">PCB 類型</th><th style="text-align:left;">關鍵材料</th><th style="text-align:left;">台灣供應商</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>5G 基地台</strong></td><td style="text-align:left;">多層板、高頻板</td><td style="text-align:left;">Rogers/PTFE 材料</td><td style="text-align:left;">健鼎、華通</td></tr><tr><td style="text-align:left;"><strong>6G 研發</strong></td><td style="text-align:left;">毫米波高頻板</td><td style="text-align:left;">Low Loss CCL + PTFE</td><td style="text-align:left;">台光電、聯茂</td></tr><tr><td style="text-align:left;"><strong>低軌衛星 RF</strong></td><td style="text-align:left;">高頻 PCB</td><td style="text-align:left;">PTFE/Rogers 材料</td><td style="text-align:left;">華通（LEO）</td></tr><tr><td style="text-align:left;"><strong>衛星通訊終端</strong></td><td style="text-align:left;">HDI + RF 混合板</td><td style="text-align:left;">低損耗材料</td><td style="text-align:left;">華通、燿華</td></tr></tbody></table><hr><h2 id="_4-半導體測試用-pcb" tabindex="-1">4. 半導體測試用 PCB <a class="header-anchor" href="#_4-半導體測試用-pcb" aria-label="Permalink to &quot;4. 半導體測試用 PCB&quot;">​</a></h2><h3 id="封裝測試板市場" tabindex="-1">封裝測試板市場 <a class="header-anchor" href="#封裝測試板市場" aria-label="Permalink to &quot;封裝測試板市場&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">類型</th><th style="text-align:left;">說明</th><th style="text-align:left;">台灣供應商</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Probe Card PCB</strong></td><td style="text-align:left;">晶圓測試用高精密板</td><td style="text-align:left;">雍智科、穎崴等</td></tr><tr><td style="text-align:left;"><strong>Load Board PCB</strong></td><td style="text-align:left;">最終測試用板</td><td style="text-align:left;">旺矽、雍智科等</td></tr><tr><td style="text-align:left;"><strong>IC 載板</strong></td><td style="text-align:left;">ABF/BT 載板（見 ABF 報告）</td><td style="text-align:left;">欣興、南電、景碩</td></tr></tbody></table><blockquote><p><strong>註</strong>：半導體測試板為利基型市場，部分供應商已納入審計資料庫。</p></blockquote><hr><h2 id="_5-風險因素" tabindex="-1">5. 風險因素 <a class="header-anchor" href="#_5-風險因素" aria-label="Permalink to &quot;5. 風險因素&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">風險</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Starlink 垂直整合</strong></td><td style="text-align:left;">SpaceX 自建 Bastrop PCB 廠，外部供應商可能受限</td></tr><tr><td style="text-align:left;"><strong>LEO 衛星發射延遲</strong></td><td style="text-align:left;">Starship 火箭進度影響 V3 衛星部署時程</td></tr><tr><td style="text-align:left;"><strong>車用電子景氣循環</strong></td><td style="text-align:left;">EV 銷量波動影響 PCB 訂單</td></tr><tr><td style="text-align:left;"><strong>技術替代</strong>：玻璃基板長期可能影響部分應用</td><td style="text-align:left;"></td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>PCMag</strong> (2025): Starlink Bastrop 廠年產 8M kits → 16M (2026), &gt;9,000 顆衛星</li><li><strong>CTEE</strong> (2026/02): 華通 2025 營收 ~NT$760B, LEO 板 &gt;NT$151B (20–22%)</li><li><strong>CTEE / cnyes</strong> (2026/05): 華通 2026 LEO 板營收挑戰 NT$200B (26%+)</li><li><strong>digitimes</strong> (2026/05): 華通泰國新廠月產能 40 萬平方英尺</li><li><strong>PCB Directory</strong> (2025): SpaceX Bastrop 廠為美國最大 PCB 製造廠</li><li><strong>STMicroelectronics</strong> (2025): 十年合作，供應 Starlink 相控陣列天線晶片</li></ol>',34)])])}const y=e(s,[["render",n]]);export{f as __pageData,y as default};
